func (a *adapter) SomeMutation(ctx context.Context, params planaddon.SomeMutationInput) (*planaddon.PlanAddon, error) {
	fn := func(ctx context.Context, a *adapter) (*planaddon.PlanAddon, error) {
		if err := params.Validate(); err != nil {
			return nil, fmt.Errorf("invalid params: %w", err)
		}
		row, err := a.db.PlanAddon.UpdateOneID(params.ID).
			Where(planaddondb.Namespace(params.Namespace)).
			SetSomeField(params.SomeField).
			Save(ctx)
		if err != nil {
			if entdb.IsNotFound(err) {
				return nil, planaddon.NewNotFoundError(planaddon.NotFoundErrorParams{Namespace: params.Namespace, ID: params.ID})
			}
			return nil, fmt.Errorf("failed to mutate: %w", err)
		}
		// refetch with eager loads...
		_ = row
		return a.GetPlanAddon(ctx, planaddon.GetPlanAddonInput{NamespacedModel: models.NamespacedModel{Namespace: params.Namespace}, ID: params.ID})
	}
	return entutils.TransactingRepo[*planaddon.PlanAddon, *adapter](ctx, a, fn)
}

type (
	MyNewRequest  = planaddon.MyNewInput
	MyNewResponse = api.PlanAddon
	MyNewParams   struct{ PlanIDOrKey string }
	MyNewHandler  httptransport.HandlerWithArgs[MyNewRequest, MyNewResponse, MyNewParams]
)

func (h *handler) MyNew() MyNewHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, params MyNewParams) (MyNewRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return MyNewRequest{}, err
			}
			return MyNewRequest{NamespacedModel: models.NamespacedModel{Namespace: ns}, PlanIDOrKey: params.PlanIDOrKey}, nil
		},
		func(ctx context.Context, request MyNewRequest) (MyNewResponse, error) {
			a, err := h.service.MyNew(ctx, request)
			if err != nil {
				return MyNewResponse{}, err
			}
			return FromPlanAddon(*a)
		},
		commonhttp.JSONResponseEncoderWithStatus[MyNewResponse](http.StatusOK),
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("myNew"),
			httptransport.WithErrorEncoder(productcataloghttp.ValidationErrorEncoder(productcataloghttp.ResourceKindAddon)),
		)...,
	)
}

func (s service) SomeMutation(ctx context.Context, params planaddon.SomeMutationInput) (*planaddon.PlanAddon, error) {
	fn := func(ctx context.Context) (*planaddon.PlanAddon, error) {
		if err := params.Validate(); err != nil {
			return nil, fmt.Errorf("invalid params: %w", err)
		}
		pa, err := s.adapter.SomeMutation(ctx, params)
		if err != nil {
			if notFound := &(planaddon.NotFoundError{}); errors.As(err, &notFound) {
				return nil, models.NewGenericNotFoundError(err)
			}
			return nil, fmt.Errorf("failed to mutate: %w", err)
		}
		event := planaddon.NewPlanAddonUpdateEvent(ctx, pa)
		if err = s.publisher.Publish(ctx, event); err != nil {
			return nil, fmt.Errorf("failed to publish event: %w", err)
		}
		return pa, nil
	}
	return transaction.Run(ctx, s.adapter, fn)
}
